llm_verdict.message:
{
  "plan_description": "Modify /etc/security/pwquality.conf to set the pam_pwquality difok parameter to 4, ensuring that new passwords must differ from the old password by at least 4 characters.",
  "commands": [
    {
      "command": "sed -i '/^#*\\s*difok\\s*=.*/difok = 4/' /etc/security/pwquality.conf"
    },
    {
      "command": "sh -c 'if ! grep -q \"^difok=\" /etc/security/pwquality.conf; then echo \"difok = 4\" >> /etc/security/pwquality.conf'"
    }
  ]
}

